export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:05。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "醫務室。門口。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校安走了。走廊上的人流把他引到了另一頭。對講機的聲音越來越遠。門口空了。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言從轉角走出來。三步。五步。到門口。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門半掩著。他沒有推開。他把身體側過來，從門縫的角度往裡看。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "內間。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "燈全亮著。冷的白色熒光燈。和第三章一樣的燈。一樣的桌面。一樣的藥品櫃。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但不一樣。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "靠牆的位置。那裡原本放著兩台冰敷櫃。一號和二號。白漆鐵皮。上面貼著編號標籤。第三章顧言在醫務室死亡前，曾經撞到過二號冰敷櫃的邊角——冰敷袋從裡面滑出來，砸在他的腳背上。他知道那個櫃子的位置。他知道那個櫃子長什麼樣。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "二號冰敷櫃不在原位了。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "它被拉出來了。從靠牆的位置拖到了房間中間。輪子在地板上留下了兩道平行的刮痕。櫃門開著。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）二號冰敷櫃。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）被拉出來了。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的眼睛釘在櫃門上。櫃門內側。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一張標籤。紅色的。貼在櫃門內側的金屬面上。手寫的。紅色馬克筆。幾個字——盤點編號、日期、簽名欄。格式像校內器材盤點表。但顏色是紅色的。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）紅色標籤。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）櫃門內側。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）和我告訴邵叔的一模一樣。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我說的是——「我會在櫃門裡側貼一張紅色盤點標籤。只有我知道。」", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）紅色。盤點標籤。櫃門內側。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）全部命中。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的手指扣在門框上。指節發白。他沒有感覺。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他繼續看。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "二號冰敷櫃旁邊。地上。放著一個袋子。深藍色的。上面印著白色的字——校安失物保管袋。拉鏈開著。裡面是空的。旁邊放著一張登記卡。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）校安失物保管袋。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這不是醫務室的東西。這是校安的。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）醫務室裡放著校安的失物保管袋——", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）有人在這裡準備接收「學生物品」。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌上。登記表。攤開著。顧言從門縫的角度能看見表頭。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「學生物品暫存／醫療器材盤點」。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）學生物品暫存。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）醫療器材盤點。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）兩個名義疊在一張表上。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）如果我真的把相機放進二號冰敷櫃——", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這套流程會把相機變成「學生物品暫存物」。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）用「醫療器材盤點」的名義封存。用校安失物保管袋裝走。用登記表登記。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）每一個步驟都合法。每一個步驟都合理。每一個步驟都看不出是誰下的令。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這比毒藥可怕。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）毒藥至少能被驗出來。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）這套流程——就算被人看見，也只會覺得是校慶閉幕前的例行安全確認。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言從門縫退回來。一步。兩步。退回轉角。靠在牆上。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的臉沒有表情。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是平靜。是空了。像一張被抽掉了所有內容的紙。眉心的皺紋還在。眼睛還是開著的。但裡面沒有東西在動。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "安靜到可怕。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠站在他旁邊。她看見了他的臉。她的手指在相機背帶上收緊了一下。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你看見了什麼。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有立刻回答。他靠在牆上。呼吸很淺。很慢。像在數自己的心跳。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "二號冰敷櫃。被拉出原位。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "櫃門內側。紅色盤點標籤。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "旁邊。校安失物保管袋。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "桌上。登記表。學生物品暫存。醫療器材盤點。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他一條一條地說。聲音很平。平到像在念一份清單。沒有起伏。沒有顫抖。沒有憤怒。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但許星棠聽出了別的東西。她聽出的是——他太平了。平到不正常。像一個人在崩潰之前，把所有情緒先搬走了，只留下一個空殼在說話。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "除了我們，這句話你還告訴過誰？", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.XuXingtang_Urgent },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的聲音很低。低到只有兩個人能聽見。但每個字都很清楚。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有立刻回答。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看著走廊盡頭的窗戶。雨在玻璃上。熒光燈在水膜上反光。他的眼睛對著那片光，但焦距不在那裡。焦距在更遠的地方。在記憶裡。在今天早上。在禮堂側廊。在邵叔按住他肩膀的那隻手裡。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只有他。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很久。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他才開口。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "只有他。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "韓越不知道二號冰敷櫃。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "林主任不知道紅色標籤。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "完整版本——", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "只有邵叔。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "走廊上的熒光燈嗡了一聲。雨打在窗戶上。遠處禮堂方向傳來閉幕活動的音樂聲。很模糊。像隔了一層水。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠沒有說話。她看著顧言。他的側臉在熒光燈下很白。嘴唇抿著。眼睛沒有濕——但比濕更讓人不安。是乾的。是完全乾的。像眼淚在到達眼睛之前就被蒸發了。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言站在那裡。很安靜。安靜到可怕。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他在腦中把三條線排開了。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第一條。鐘樓天線屋。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我告訴韓越——鐘樓天線屋可能是備用傳輸點。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）結果：無新增反應。沒有封鎖。沒有校安。沒有陷阱。韓越沒有靠近鐘樓。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）結論：韓越不是外洩源。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第二條。基座左側暗槽。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我告訴林主任——基座底板左側暗槽裡可能有密碼提示。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）結果：林主任提前出現在基座旁。他蹲下來找左側。他找到了位置。他沒有打開。他封鎖了。他打電話回報。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）結論：林主任是執行者。或共犯。他在補救。在封堵。在聽命。不是設計全局的人。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）第三條。醫務室二號冰敷櫃。紅色盤點標籤。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我告訴邵叔——相機會藏在醫務室二號冰敷櫃。櫃門內側貼紅色盤點標籤。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）結果：二號冰敷櫃被拉出原位。櫃門內側貼著紅色盤點標籤。旁邊放著校安失物保管袋。桌上登記表寫著學生物品暫存和醫療器材盤點。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）結論：完整命中。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）韓越不知道二號冰敷櫃。林主任不知道紅色標籤。核心同盟之外，完整知道這些細節的——", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）只有邵叔。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）是他。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言的手從牆上滑下來。他低頭看了一眼自己的手。手指在抖。很輕。不仔細看看不出來。但在抖。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有哭。他沒有喊。他沒有砸牆。他沒有跑。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他只是站在那裡。站在南翼醫務室外側走廊的轉角。站在熒光燈下面。站在雨聲和遠處音樂聲的中間。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "安靜到可怕。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "你確定了。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是問句。是確認。她的聲音很平。像在蓋章。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "嗯。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠沒有再問。她沒有說「我很抱歉」。沒有說「你還好嗎」。她只是站在那裡。和他一起站在走廊轉角。像兩根柱子。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "過了很久。也許十秒。也許三十秒。在雨聲裡分不清楚。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.XuXingtang, character: "許星棠", dialogue: "還能走嗎。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.XuXingtang_Cold },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言沒有立刻回答。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把手插進口袋。口袋裡有筆記本。他摸到了筆記本的硬皮封面。指尖碰到了紙頁的邊緣。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）邵叔。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你照顧了我七年。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你問我吃了沒有。你幫我帶外套。你在我不說話的時候不追問。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）你每一次溫柔的詢問——", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）都是審問。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Sad },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）走。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）還得走。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）知道是誰不是結束。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）證據還沒出去。密碼還沒解。23:00還在前面。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）她還會死。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）⋯⋯", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）但我現在知道了。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "（內心）我知道該騙過誰了。", background: Background.Chapter_7_Ch7_Act12_S0, portrait: Portrait.GuYan_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從牆邊撐起來。直了直背。校服濕透了，貼在肩上，很沉。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "許星棠看了他一眼。沒有說話。她轉身。往走廊另一頭走。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言跟上去。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "身後，醫務室的門半掩著。內間的燈還亮著。二號冰敷櫃站在房間中間。櫃門開著。紅色標籤在冷光裡很亮。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "像一個陷阱。一個只有邵叔知道怎麼布置的陷阱。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個顧言親手遞過去鑰匙的陷阱。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "22:10。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "三條線。交叉完畢。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "韓越。乾淨。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "林主任。執行者。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "邵叔。情報源。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨還在下。23:00還有五十分鐘。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "顧言走在走廊上。腳步聲踩過積水。很穩。很慢。像一個已經知道答案、但還不知道怎麼用答案的人。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他知道邵叔是誰了。", background: Background.Chapter_7_Ch7_Act12_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但他還不知道——怎麼在邵叔面前，活過今晚。", background: Background.Chapter_7_Ch7_Act12_S0 },
];
